/* ---------------- التنقل الرئيسي ---------------- */
const NavBar = ({ navigate }) => {
  const { t, dark } = useLang();
  const NAV = buildNav(t);
  const [open, setOpen] = useState(null);
  const [mobileOpen, setMobileOpen] = useState(false);
  const [mobileSub, setMobileSub] = useState(null);
  const closeTimer = useRef(null);

  const enter = (key) => { clearTimeout(closeTimer.current); setOpen(key); };
  const leave = () => { closeTimer.current = setTimeout(() => setOpen(null), 150); };

  const handleNavClick = (item) => {
    if (item.children) {
      setOpen((cur) => (cur === item.key ? null : item.key));
    } else {
      navigate(item.key);
      setOpen(null);
    }
  };

  const handleChildClick = (item, idx) => {
    if (item.anchors) {
      navigate(item.key, { anchor: item.anchors[idx] });
    } else {
      navigate(item.key);
    }
    setOpen(null);
    setMobileOpen(false);
    setMobileSub(null);
  };

  useEffect(() => {
    const onDocClick = (e) => {
      if (!e.target.closest || !e.target.closest("[data-navroot]")) setOpen(null);
    };
    document.addEventListener("click", onDocClick);
    return () => document.removeEventListener("click", onDocClick);
  }, []);

  return (
    <div style={{ background: C.paper, position: "sticky", top: 0, zIndex: 50, boxShadow: "0 2px 18px rgba(0,0,0,0.08)", borderBottom: `1px solid ${C.line}` }}>
      <div className="container" style={{ display: "flex", alignItems: "center", justifyContent: "space-between", paddingTop: 14, paddingBottom: 14 }}>
        <div style={{ cursor: "pointer" }} onClick={() => navigate("home")}>
          <Logo dark={dark} image={dark ? LOGO_DATA_URI : logo2} />
        </div>

        <nav style={{ display: "flex", alignItems: "center", gap: 2 }} className="desktop-nav" data-navroot>
          {NAV.map((item) => (
            <div key={item.key} onMouseEnter={() => item.children && enter(item.key)} onMouseLeave={() => item.children && leave()} style={{ position: "relative" }}>
              <button
                type="button"
                onClick={() => handleNavClick(item)}
                aria-expanded={item.children ? open === item.key : undefined}
                aria-haspopup={item.children ? "true" : undefined}
                className="nav-link"
                style={{
                  background: "transparent", border: "none",
                  color: open === item.key ? C.emerald : C.text,
                  fontFamily: "Tajawal", fontWeight: 500, fontSize: 14.5,
                  padding: "10px 12px", cursor: "pointer", display: "flex",
                  alignItems: "center", gap: 5, position: "relative",
                  transition: "color .25s", whiteSpace: "nowrap",
                }}
              >
                {item.badge && (
                  <span style={{ position: "absolute", top: -2, insetInlineEnd: -6, background: C.crimson, color: "#fff", fontSize: 9, fontFamily: "Tajawal", fontWeight: 700, padding: "1.5px 5px", borderRadius: 6 }}>
                    {item.badge}
                  </span>
                )}
                {item.label}
                {item.children && (
                  <span style={{ transform: open === item.key ? "rotate(180deg)" : "none", transition: "transform .25s", display: "flex" }}>
                    <Icon name="chevron" size={13} />
                  </span>
                )}
              </button>

              {item.children && open === item.key && (
                <div style={{ position: "absolute", top: "100%", insetInlineEnd: 0, minWidth: 260, background: C.paper, borderRadius: 12, boxShadow: "0 18px 40px rgba(0,0,0,0.16)", overflow: "hidden", border: `1px solid ${C.line}`, animation: "dropdownIn .2s cubic-bezier(.22,.61,.36,1)" }}>
                  {item.children.map((c, idx) => (
                    <a
                      key={idx}
                      href="#"
                      onClick={(e) => { e.preventDefault(); handleChildClick(item, idx); }}
                      style={{ display: "block", padding: "13px 18px", fontFamily: "Tajawal", fontSize: 14, color: C.text, textDecoration: "none", borderBottom: idx !== item.children.length - 1 ? `1px solid ${C.sandDark}` : "none", transition: "background .18s, color .18s, padding-inline-start .18s" }}
                      onMouseEnter={(e) => { e.currentTarget.style.background = C.emeraldPale; e.currentTarget.style.color = C.emerald; e.currentTarget.style.paddingInlineStart = "22px"; }}
                      onMouseLeave={(e) => { e.currentTarget.style.background = "transparent"; e.currentTarget.style.color = C.text; e.currentTarget.style.paddingInlineStart = "18px"; }}
                    >
                      {c}
                    </a>
                  ))}
                </div>
              )}
            </div>
          ))}
        </nav>

        <button
          className="mobile-toggle"
          onClick={() => setMobileOpen((v) => !v)}
          style={{ display: "none", background: C.sand, border: `1px solid ${C.line}`, borderRadius: 10, width: 40, height: 40, color: C.text, fontSize: 18, cursor: "pointer" }}
        >
          {mobileOpen ? "✕" : "☰"}
        </button>
      </div>

      {mobileOpen && (
        <div className="mobile-menu" style={{ background: C.sand, padding: "6px 16px 16px", display: "none" }}>
          {NAV.map((item) => (
            <div key={item.key} style={{ borderBottom: `1px solid ${C.line}` }}>
              <button
                type="button"
                onClick={() => {
                  if (item.children) {
                    setMobileSub(mobileSub === item.key ? null : item.key);
                  } else {
                    navigate(item.key);
                    setMobileOpen(false);
                  }
                }}
                style={{ width: "100%", background: "transparent", border: "none", color: C.text, fontFamily: "Tajawal", fontSize: 15, padding: "13px 4px", display: "flex", justifyContent: "space-between", alignItems: "center", cursor: "pointer" }}
              >
                <span>{item.label}</span>
                {item.children && <span style={{ transform: mobileSub === item.key ? "rotate(180deg)" : "none", transition: "transform .25s" }}><Icon name="chevron" size={14} color={C.muted} /></span>}
              </button>
              {item.children && mobileSub === item.key && (
                <div style={{ paddingBottom: 8 }}>
                  {item.children.map((c, idx) => (
                    <a key={idx} href="#" onClick={(e) => { e.preventDefault(); handleChildClick(item, idx); }} style={{ display: "block", padding: "9px 14px", fontFamily: "Tajawal", fontSize: 13.5, color: C.muted, textDecoration: "none" }}>
                      ‹ {c}
                    </a>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

