/* ---------------- تهجئة الكلمة الأخيرة بلغة الإشارة ---------------- */
const AR_LETTERS = "ابتثجحخدذرزسشصضطظعغفقكلمنهوياىءآأؤإئة".split("");
const EN_LETTERS = "abcdefghijklmnopqrstuvwxyz".split("");
const FingerspellRow = ({ word, lang }) => {
  const { t } = useLang();
  const alphabet = lang === "ar" ? AR_LETTERS : EN_LETTERS;
  const letters = (word || "").toLowerCase().split("").filter((ch) => alphabet.includes(ch));
  const [active, setActive] = useState(0);

  useEffect(() => {
    setActive(0);
    if (letters.length < 2) return;
    const timer = setInterval(() => setActive((v) => (v + 1) % letters.length), 550);
    return () => clearInterval(timer);
    // eslint-disable-next-line
  }, [word]);

  if (!letters.length) {
    return <div style={{ fontFamily: "Tajawal", fontSize: 12.5, color: C.muted, textAlign: "center", padding: "10px 0" }}>{t.sign.fingerspellEmpty}</div>;
  }

  return (
    <div style={{ display: "flex", gap: 8, flexWrap: "wrap", justifyContent: "center", padding: "10px 4px" }}>
      {letters.map((ch, i) => (
        <div
          key={i}
          style={{
            width: 34, height: 34, borderRadius: 10, display: "flex", alignItems: "center", justifyContent: "center",
            fontFamily: "Almarai", fontWeight: 800, fontSize: 15,
            background: i === active ? C.emerald : C.sandDark,
            color: i === active ? "#fff" : C.muted,
            transform: i === active ? "translateY(-4px) scale(1.08)" : "none",
            transition: "all .28s cubic-bezier(.22,.61,.36,1)",
            border: i === active ? `1px solid ${C.emeraldLight}` : `1px solid ${C.line}`,
            textTransform: "uppercase",
          }}
        >
          {ch}
        </div>
      ))}
    </div>
  );
};

/* ---------------- تواصل بلغة الإشارة (يعمل بالصوت أو بالكتابة) ---------------- */
const SignLanguageWidget = () => {
  const { t, lang } = useLang();
  const [open, setOpen] = useState(false);
  const [listening, setListening] = useState(false);
  const [supported, setSupported] = useState(true);
  const [micError, setMicError] = useState("");
  const [transcript, setTranscript] = useState("");
  const [interim, setInterim] = useState("");
  const [typed, setTyped] = useState("");
  const [lastWord, setLastWord] = useState("");
  const recRef = useRef(null);

  useEffect(() => {
    const SR = typeof window !== "undefined" && (window.SpeechRecognition || window.webkitSpeechRecognition);
    if (!SR) {
      setSupported(false);
      return;
    }
    try {
      const rec = new SR();
      rec.lang = lang === "ar" ? "ar-AE" : "en-US";
      rec.continuous = true;
      rec.interimResults = true;

      rec.onresult = (event) => {
        let finalText = "";
        let interimText = "";
        for (let i = event.resultIndex; i < event.results.length; i++) {
          const tx = event.results[i][0].transcript;
          if (event.results[i].isFinal) finalText += tx;
          else interimText += tx;
        }
        if (finalText.trim()) {
          setTranscript((prev) => (prev ? prev + " " + finalText.trim() : finalText.trim()));
          const words = finalText.trim().split(/\s+/);
          setLastWord(words[words.length - 1] || "");
        }
        setInterim(interimText);
      };
      rec.onerror = (e) => {
        setListening(false);
        if (e && e.error === "not-allowed") setMicError(t.sign.micDenied);
      };
      rec.onend = () => setListening(false);
      recRef.current = rec;
    } catch (err) {
      setSupported(false);
    }

    return () => {
      try { recRef.current && recRef.current.stop(); } catch (e) {}
    };
    // eslint-disable-next-line
  }, [lang]);

  const toggleListening = () => {
    if (!recRef.current) {
      setMicError(t.sign.micUnsupported);
      return;
    }
    if (listening) {
      recRef.current.stop();
      setListening(false);
    } else {
      setMicError("");
      setTranscript("");
      setInterim("");
      try {
        recRef.current.start();
        setListening(true);
      } catch (e) {
        setMicError(t.sign.micUnsupported);
      }
    }
  };

  const onTypeChange = (e) => {
    const val = e.target.value;
    setTyped(val);
    const words = val.trim().split(/\s+/);
    setLastWord(words[words.length - 1] || "");
  };

  return (
    <div style={{ position: "fixed", insetInlineStart: 22, bottom: 22, zIndex: 60 }}>
      {open && (
        <div style={{ position: "absolute", bottom: 66, insetInlineStart: 0, width: "min(340px, 88vw)", background: C.paper, border: `1px solid ${C.line}`, borderRadius: 18, boxShadow: "0 24px 60px rgba(0,0,0,0.28)", overflow: "hidden", animation: "panelIn .25s cubic-bezier(.22,.61,.36,1)" }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "14px 16px", borderBottom: `1px solid ${C.line}`, background: C.emeraldPale }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8, color: C.text, fontFamily: "Almarai", fontWeight: 700, fontSize: 14 }}>
              <Icon name="hand" size={17} color={C.emerald} /> {t.sign.title}
            </div>
            <button type="button" onClick={() => setOpen(false)} style={{ background: "transparent", border: "none", color: C.muted, cursor: "pointer" }}>
              <Icon name="close" size={16} />
            </button>
          </div>

          <div style={{ padding: "16px" }}>
            <button
              type="button"
              onClick={toggleListening}
              style={{
                width: "100%", display: "flex", alignItems: "center", justifyContent: "center", gap: 10,
                background: listening ? C.crimson : C.emerald, color: "#fff", border: "none", borderRadius: 12,
                padding: "12px 16px", fontFamily: "Tajawal", fontWeight: 700, fontSize: 14, cursor: "pointer", marginBottom: 10,
                transition: "background .25s ease, transform .15s ease",
              }}
            >
              <Icon name="mic" size={17} />
              {listening ? t.sign.stopListen : t.sign.startListen}
              {listening && <span style={{ width: 8, height: 8, borderRadius: 99, background: "#fff", animation: "pulseDot 1s ease-in-out infinite" }} />}
            </button>

            {(!supported || micError) && (
              <div style={{ fontFamily: "Tajawal", fontSize: 12, color: C.crimson, lineHeight: 1.8, marginBottom: 10 }}>
                {micError || t.sign.micUnsupported}
              </div>
            )}

            <div style={{ background: C.sand, border: `1px solid ${C.line}`, borderRadius: 12, padding: "12px 14px", minHeight: 46, fontFamily: "Tajawal", fontSize: 14, color: C.text, lineHeight: 1.8, marginBottom: 14 }}>
              {transcript || interim ? (<>{transcript} <span style={{ color: C.muted }}>{interim}</span></>) : (<span style={{ color: C.muted }}>{t.sign.placeholderText}</span>)}
            </div>

            <div style={{ fontFamily: "Tajawal", fontSize: 11.5, color: C.muted, marginBottom: 6 }}>{t.sign.typeLabel}</div>
            <input
              value={typed}
              onChange={onTypeChange}
              placeholder={t.sign.typePlaceholder}
              style={{ width: "100%", background: C.sand, border: `1px solid ${C.line}`, borderRadius: 10, padding: "10px 12px", color: C.text, fontFamily: "Tajawal", fontSize: 13.5, outline: "none", marginBottom: 14 }}
            />

            <div style={{ borderTop: `1px solid ${C.line}`, paddingTop: 8 }}>
              <div style={{ fontFamily: "Tajawal", fontSize: 11.5, color: C.muted, textAlign: "center", marginBottom: 4 }}>{t.sign.fingerspellTitle}</div>
              <FingerspellRow word={lastWord} lang={lang} />
            </div>
            <div style={{ fontFamily: "Tajawal", fontSize: 10.5, color: C.muted, textAlign: "center", marginTop: 6 }}>{t.sign.note}</div>
          </div>
        </div>
      )}

      <button
        type="button"
        onClick={() => setOpen((v) => !v)}
        className="floating-btn"
        style={{ display: "flex", alignItems: "center", gap: 10, background: C.emerald, color: "#fff", border: "none", borderRadius: 99, padding: "13px 20px", fontFamily: "Tajawal", fontWeight: 700, fontSize: 13.5, cursor: "pointer", boxShadow: "0 12px 30px rgba(14,124,90,0.4)", position: "relative" }}
      >
        <span style={{ position: "absolute", inset: -4, borderRadius: 99, border: `2px solid ${C.emeraldLight}`, animation: "ring 1.8s ease-out infinite" }} />
        <Icon name={open ? "close" : "hand"} size={18} /> {t.sign.floating}
      </button>
    </div>
  );
};

/* ---------------- المساعد الذكي ---------------- */
const AiBot = () => {
  const { t } = useLang();
  const [open, setOpen] = useState(false);
  const [messages, setMessages] = useState([{ from: "bot", text: t.bot.hello }]);
  const [input, setInput] = useState("");
  const [typing, setTyping] = useState(false);
  const boxRef = useRef(null);

  useEffect(() => { setMessages([{ from: "bot", text: t.bot.hello }]); }, [t]);
  useEffect(() => { if (boxRef.current) boxRef.current.scrollTop = boxRef.current.scrollHeight; }, [messages, typing]);

  const findAnswer = (msg) => {
    const clean = msg.trim().toLowerCase();
    for (const item of t.bot.faq) {
      if (item.k.some((kw) => clean.includes(kw.toLowerCase()))) return item.a;
    }
    return t.bot.fallback;
  };

  const send = (e) => {
    e.preventDefault();
    const text = input.trim();
    if (!text) return;
    setMessages((m) => [...m, { from: "user", text }]);
    setInput("");
    setTyping(true);
    setTimeout(() => {
      setMessages((m) => [...m, { from: "bot", text: findAnswer(text) }]);
      setTyping(false);
    }, 550);
  };

  return (
    <div style={{ position: "fixed", insetInlineEnd: 22, bottom: 22, zIndex: 60 }}>
      {open && (
        <div style={{ position: "absolute", bottom: 66, insetInlineEnd: 0, width: "min(350px, 88vw)", height: 440, background: C.paper, border: `1px solid ${C.line}`, borderRadius: 18, boxShadow: "0 24px 60px rgba(0,0,0,0.32)", overflow: "hidden", display: "flex", flexDirection: "column", animation: "panelIn .25s cubic-bezier(.22,.61,.36,1)" }}>
          <div style={{ background: C.emeraldPale, padding: "14px 16px", display: "flex", alignItems: "center", justifyContent: "space-between", borderBottom: `1px solid ${C.line}` }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8, color: C.text, fontFamily: "Almarai", fontWeight: 700, fontSize: 14 }}>
              <Icon name="sparkle" size={17} color={C.emerald} /> {t.bot.title}
            </div>
            <button type="button" onClick={() => setOpen(false)} style={{ background: "transparent", border: "none", color: C.muted, cursor: "pointer" }}>
              <Icon name="close" size={16} />
            </button>
          </div>

          <div ref={boxRef} style={{ flex: 1, overflowY: "auto", padding: "16px", display: "flex", flexDirection: "column", gap: 10, background: C.sand }}>
            {messages.map((m, i) => (
              <div key={i} className="chat-bubble" style={{ alignSelf: m.from === "bot" ? "flex-start" : "flex-end", maxWidth: "82%", background: m.from === "bot" ? C.paper : C.emerald, color: m.from === "bot" ? C.text : "#fff", border: m.from === "bot" ? `1px solid ${C.line}` : "none", borderRadius: 14, padding: "10px 14px", fontFamily: "Tajawal", fontSize: 13.5, lineHeight: 1.8 }}>
                {m.text}
              </div>
            ))}
            {typing && (
              <div style={{ alignSelf: "flex-start", color: C.muted, fontFamily: "Tajawal", fontSize: 12.5, display: "flex", gap: 4, alignItems: "center" }}>
                <span style={{ width: 6, height: 6, borderRadius: 99, background: C.muted, animation: "pulseDot 1s infinite" }} />
                <span style={{ width: 6, height: 6, borderRadius: 99, background: C.muted, animation: "pulseDot 1s .15s infinite" }} />
                <span style={{ width: 6, height: 6, borderRadius: 99, background: C.muted, animation: "pulseDot 1s .3s infinite" }} />
              </div>
            )}
          </div>

          <form onSubmit={send} style={{ display: "flex", gap: 8, padding: 12, borderTop: `1px solid ${C.line}`, background: C.paper }}>
            <input value={input} onChange={(e) => setInput(e.target.value)} placeholder={t.bot.placeholder} style={{ flex: 1, border: `1px solid ${C.line}`, borderRadius: 10, padding: "10px 14px", fontFamily: "Tajawal", fontSize: 13.5, outline: "none", color: C.text, background: C.paper }} />
            <button type="submit" style={{ background: C.emerald, color: "#fff", border: "none", borderRadius: 10, width: 42, display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer" }}>
              <Icon name="send" size={17} />
            </button>
          </form>
        </div>
      )}

      <button
        type="button"
        onClick={() => setOpen((v) => !v)}
        className="floating-btn"
        style={{ width: 58, height: 58, borderRadius: 99, background: C.emerald, color: "#fff", border: "none", display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", boxShadow: "0 12px 30px rgba(14,124,90,0.4)" }}
        aria-label={t.bot.title}
      >
        <Icon name={open ? "close" : "chat"} size={22} color="#fff" />
      </button>
    </div>
  );
};

